export interface MagicPet {
  name: string;
  baseAnimal: string;
  element: string;
  personality: string;
  imageUrl?: string;
  story?: string;
}

export type AppState = 'HOME' | 'CREATOR' | 'RESULT' | 'GALLERY';

export interface BaseAnimal {
  id: string;
  name: string;
  icon: string;
  color: string;
}

export interface MagicElement {
  id: string;
  name: string;
  icon: string;
  color: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { MagicPet } from "../types";

export const generatePetImage = async (pet: MagicPet): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const prompt = `A very cute, friendly, and magical ${pet.baseAnimal} with ${pet.element} powers. 
    Digital 3D art style like Pixar or Disney, vibrant bright colors, happy expression, 
    magical sparkles, clean background. The pet looks like it belongs in a children's fantasy world.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image part found in response");
  } catch (error) {
    console.error("Error generating image:", error);
    // Fallback to a placeholder
    return `https://picsum.photos/seed/${pet.name}/512/512`;
  }
};

export const generatePetStory = async (pet: MagicPet): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const prompt = `Escribe un cuento muy corto (3-4 frases) para un niño pequeño sobre una mascota mágica llamada ${pet.name}. 
    Es un ${pet.baseAnimal} con poderes de ${pet.element}. Su personalidad es ${pet.personality}. 
    Asegúrate de que sea una historia feliz y mágica.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "¡Tu mascota está lista para jugar!";
  } catch (error) {
    console.error("Error generating story:", error);
    return `¡Había una vez un valiente ${pet.baseAnimal} llamado ${pet.name} que amaba el ${pet.element}!`;
  }
};

import React from 'react';

interface MagicButtonProps {
  onClick: () => void;
  children: React.ReactNode;
  className?: string;
  disabled?: boolean;
  variant?: 'primary' | 'secondary' | 'accent';
}

const MagicButton: React.FC<MagicButtonProps> = ({ 
  onClick, 
  children, 
  className = "", 
  disabled = false,
  variant = 'primary' 
}) => {
  const variants = {
    primary: 'bg-yellow-400 hover:bg-yellow-300 text-yellow-900 border-b-4 border-yellow-600',
    secondary: 'bg-blue-400 hover:bg-blue-300 text-white border-b-4 border-blue-600',
    accent: 'bg-pink-400 hover:bg-pink-300 text-white border-b-4 border-pink-600',
  };

  return (
    <button
      onClick={onClick}
      disabled={disabled}
      className={`
        px-8 py-3 rounded-full font-bold text-lg 
        transition-all duration-200 active:translate-y-1 active:border-b-0
        disabled:opacity-50 disabled:cursor-not-allowed
        ${variants[variant]}
        ${className}
      `}
    >
      {children}
    </button>
  );
};

export default MagicButton;

