import React, { useState, useEffect, useRef } from 'react';
import { BASE_ANIMALS, COLORS_BY_NUMBER } from '../constants';

interface ColorByNumberProps {
  animalId: string;
  selectedNumber: number;
  onColored: (dataUrl: string) => void;
}

const ColorByNumber: React.FC<ColorByNumberProps> = ({ animalId, selectedNumber, onColored }) => {
  const animal = BASE_ANIMALS.find(a => a.id === animalId) || BASE_ANIMALS[0];
  const [fills, setFills] = useState<Record<string, string>>({});
  const containerRef = useRef<HTMLDivElement>(null);

  const handleRegionClick = (regionId: string) => {
    const colorObj = COLORS_BY_NUMBER.find(c => c.n === selectedNumber);
    if (colorObj) {
      const newFills = { ...fills, [regionId]: colorObj.color };
      setFills(newFills);
    }
  };

  useEffect(() => {
    // Generar imagen para la IA cuando cambie algo
    if (containerRef.current) {
      const svg = containerRef.current.querySelector('svg');
      if (svg) {
        const svgData = new XMLSerializer().serializeToString(svg);
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        const img = new Image();
        const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
        const url = URL.createObjectURL(svgBlob);

        img.onload = () => {
          canvas.width = 400;
          canvas.height = 400;
          if (ctx) {
            ctx.fillStyle = 'white';
            ctx.fillRect(0, 0, 400, 400);
            ctx.drawImage(img, 0, 0, 400, 400);
            onColored(canvas.toDataURL('image/png'));
          }
          URL.revokeObjectURL(url);
        };
        img.src = url;
      }
    }
  }, [fills]);

  return (
    <div ref={containerRef} className="w-full flex justify-center bg-white p-4 rounded-[3rem] shadow-inner border-4 border-indigo-100">
      <svg viewBox="0 0 100 100" className="w-full max-w-[350px] aspect-square select-none touch-none">
        {Object.entries(animal.pathData).map(([num, path]) => (
          <g key={num} onClick={() => handleRegionClick(num)} className="cursor-pointer">
            <path
              d={path}
              fill={fills[num] || '#f8fafc'}
              stroke="#cbd5e1"
              strokeWidth="1"
              className="transition-colors duration-300"
            />
            {!fills[num] && (
              <text
                x="50%"
                y="50%"
                textAnchor="middle"
                className="text-[6px] font-bold fill-slate-300 pointer-events-none"
                style={{ dominantBaseline: 'middle' }}
              >
                {/* Posicionamiento simple del número en el centro aproximado del path si fuera posible, 
                    aquí lo ponemos genérico pero en un SVG real usaríamos coordenadas del centroide */}
                {num}
              </text>
            )}
          </g>
        ))}
        {/* Decoración ojos genéricos para que se vea más como animal */}
        <circle cx="40" cy="45" r="2" fill="#334155" />
        <circle cx="60" cy="45" r="2" fill="#334155" />
      </svg>
    </div>
  );
};

export default ColorByNumber;

import React, { useState, useEffect } from 'react';
