import { generatePetImage, generatePetStory, speakStory } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>('HOME');
  const [pet, setPet] = useState<MagicPet>({
    name: '',
    baseAnimal: '',
    element: '',
    personality: 'Feliz'
  });
  const [drawing, setDrawing] = useState<string>('');
  const [selectedNumber, setSelectedNumber] = useState(1);
  const [loading, setLoading] = useState(false);
  const [loadingMsg, setLoadingMsg] = useState('');
  const [gallery, setGallery] = useState<MagicPet[]>([]);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [interactionEmoji, setInteractionEmoji] = useState<string | null>(null);

  useEffect(() => {
    if (loading) {
      const interval = setInterval(() => {
        setLoadingMsg(LOADING_MESSAGES[Math.floor(Math.random() * LOADING_MESSAGES.length)]);
      }, 2500);
      return () => clearInterval(interval);
    }
  }, [loading]);

  const handleCreatePet = async () => {
    if (!pet.name || !pet.baseAnimal || !pet.element || !drawing) {
      alert("¡Termina de pintar a tu amigo y dale un nombre!");
      return;
    }

    setLoading(true);
    setLoadingMsg("¡Dándole vida a tu dibujo!");

    try {
      const [imageUrl, story] = await Promise.all([
        generatePetImage(pet, drawing),
        generatePetStory(pet)
      ]);

      const newPet = { ...pet, imageUrl, story };
      setPet(newPet);
      setGallery(prev => [newPet, ...prev]);
      setState('RESULT');
    } catch (error) {
      console.error(error);
      alert("¡La magia falló un poco! Intenta de nuevo.");
    } finally {
      setLoading(false);
    }
  };

  const handleSpeak = async () => {
