          <>
            {state === 'HOME' && renderHome()}
            {state === 'SELECT_TEMPLATE' && renderSelectTemplate()}
            {state === 'CREATOR' && renderCreator()}
            {state === 'RESULT' && renderResult()}
            {state === 'GALLERY' && renderGallery()}
          </>
        )}
