    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { BASE_ANIMALS, COLORS_BY_NUMBER } from '../constants';

interface ColorByNumberProps {
  animalId: string;
  selectedNumber: number;
  onColored: (dataUrl: string) => void;
}

const ColorByNumber: React.FC<ColorByNumberProps> = ({ animalId, selectedNumber, onColored }) => {
  const animal = BASE_ANIMALS.find(a => a.id === animalId) || BASE_ANIMALS[0];
  const [fills, setFills] = useState<Record<string, string>>({});
  const containerRef = useRef<HTMLDivElement>(null);

  const handleRegionClick = (regionId: string) => {
    const colorObj = COLORS_BY_NUMBER.find(c => c.n === selectedNumber);
    if (colorObj) {
      const newFills = { ...fills, [regionId]: colorObj.color };
      setFills(newFills);
    }
  };

  useEffect(() => {
    if (containerRef.current) {
      const svg = containerRef.current.querySelector('svg');
      if (svg) {
        const svgData = new XMLSerializer().serializeToString(svg);
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        const img = new Image();
        const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
        const url = URL.createObjectURL(svgBlob);

        img.onload = () => {
          canvas.width = 512;
          canvas.height = 512;
          if (ctx) {
            ctx.fillStyle = 'white';
            ctx.fillRect(0, 0, 512, 512);
            ctx.drawImage(img, 0, 0, 512, 512);
            onColored(canvas.toDataURL('image/png'));
          }
          URL.revokeObjectURL(url);
        };
        img.src = url;
      }
    }
  }, [fills]);

  // Posiciones de los ojos ajustadas por animal para realismo
  const eyePos = {
    cat: { l: {x:40, y:55}, r: {x:60, y:55} },
    lion: { l: {x:42, y:68}, r: {x:58, y:68} },
    fox: { l: {x:38, y:72}, r: {x:62, y:72} },
    unicorn: { l: {x:32, y:62}, r: {x:48, y:62} },
    panda: { l: {x:38, y:58}, r: {x:62, y:58} },
    dragon: { l: {x:42, y:65}, r: {x:58, y:65} },
  }[animal.id] || { l: {x:42, y:55}, r: {x:58, y:55} };

  return (
    <div ref={containerRef} className="w-full flex justify-center bg-white p-6 rounded-[3.5rem] shadow-inner border-4 border-indigo-100">
      <svg viewBox="0 0 100 115" className="w-full max-w-[400px] aspect-square select-none touch-none">
        <defs>
          <filter id="softShadow" x="-20%" y="-20%" width="140%" height="140%">
            <feGaussianBlur in="SourceAlpha" stdDeviation="1" />
            <feOffset dx="0.5" dy="0.5" result="offsetblur" />
            <feComponentTransfer>
              <feFuncA type="linear" slope="0.2" />
            </feComponentTransfer>
            <feMerge>
              <feMergeNode />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
        </defs>

        {Object.entries(animal.pathData).map(([num, path]) => {
          const pos = animal.numberPositions[num] || { x: 50, y: 50 };
          return (
            <g key={num} onClick={() => handleRegionClick(num)} className="cursor-pointer group">
              <path
                d={path}
                fill={fills[num] || '#fdfdfd'}
                stroke="#d1d5db"
                strokeWidth="1.2"
                filter="url(#softShadow)"
                className="transition-all duration-300 group-hover:stroke-indigo-300"
              />
              {!fills[num] && (
                <g className="pointer-events-none">
                  <circle cx={pos.x} cy={pos.y} r="3.5" fill="white" fillOpacity="0.9" />
                  <text
                    x={pos.x}
                    y={pos.y}
                    textAnchor="middle"
                    className="text-[5px] font-black fill-slate-400"
                    style={{ dominantBaseline: 'middle' }}
                  >
                    {num}
                  </text>
                </g>
              )}
            </g>
          );
        })}

        {/* Ojos expresivos con brillo */}
        <g className="pointer-events-none">
          {/* Ojo Izquierdo */}
          <circle cx={eyePos.l.x} cy={eyePos.l.y} r="3" fill="#1e293b" />
          <circle cx={eyePos.l.x - 0.8} cy={eyePos.l.y - 0.8} r="1" fill="white" />
          {/* Ojo Derecho */}
          <circle cx={eyePos.r.x} cy={eyePos.r.y} r="3" fill="#1e293b" />
          <circle cx={eyePos.r.x - 0.8} cy={eyePos.r.y - 0.8} r="1" fill="white" />
        </g>
      </svg>
    </div>
  );
};

