import React, { useState, useEffect } from 'react';
import { AppState, MagicPet } from './types';
import { BASE_ANIMALS, ELEMENTS, LOADING_MESSAGES, COLORS_BY_NUMBER } from './constants';
import MagicButton from './components/MagicButton';
import ColorByNumber from './components/ColorByNumber';
import { generatePetImage, generatePetStory, speakStory } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>('HOME');
  const [pet, setPet] = useState<MagicPet>({
    name: '',
    baseAnimal: '',
    element: '',
    personality: 'Feliz'
  });
  const [drawing, setDrawing] = useState<string>('');
  const [selectedNumber, setSelectedNumber] = useState(1);
  const [loading, setLoading] = useState(false);
  const [loadingMsg, setLoadingMsg] = useState('');
  const [gallery, setGallery] = useState<MagicPet[]>([]);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [interactionEmoji, setInteractionEmoji] = useState<string | null>(null);

  useEffect(() => {
    if (loading) {
      const interval = setInterval(() => {
        setLoadingMsg(LOADING_MESSAGES[Math.floor(Math.random() * LOADING_MESSAGES.length)]);
      }, 3000);
      return () => clearInterval(interval);
    }
  }, [loading]);

  const handleCreatePet = async () => {
    if (!pet.name || !pet.baseAnimal || !pet.element || !drawing) {
      alert("¡Recuerda pintar todas las zonas y darle un nombre!");
      return;
    }

    setLoading(true);
    setLoadingMsg("¡Tu dibujo está cobrando vida!");

    try {
      const [imageUrl, story] = await Promise.all([
        generatePetImage(pet, drawing),
        generatePetStory(pet)
      ]);

      const newPet = { ...pet, imageUrl, story };
      setPet(newPet);
      setGallery(prev => [newPet, ...prev]);
      setState('RESULT');
    } catch (error) {
      console.error(error);
      alert("¡Hubo un pequeño error mágico! Intenta de nuevo.");
    } finally {
      setLoading(false);
    }
  };

  const handleDownload = () => {
    if (!pet.imageUrl) return;
    const link = document.createElement('a');
    link.href = pet.imageUrl;
    link.download = `${pet.name}-magico.png`;
    link.click();
  };

  const handleSpeak = async () => {
    if (!pet.story || isSpeaking) return;
    setIsSpeaking(true);
    await speakStory(pet.story);
    setTimeout(() => setIsSpeaking(false), 8000);
  };

  const renderHome = () => (
    <div className="flex flex-col items-center justify-center min-h-[80vh] text-center p-6">
      <div className="relative mb-8">
        <span className="text-9xl float-animation block drop-shadow-2xl">🎨🦁✨</span>
        <div className="absolute -top-4 -right-4 bg-white p-4 rounded-full shadow-lg animate-pulse">
           <span className="text-4xl">🪄</span>
        </div>
      </div>
      <h1 className="text-6xl md:text-8xl font-black text-indigo-700 mb-6 drop-shadow-xl tracking-tight">
        MUNDO MÁGICO
      </h1>
      <p className="text-3xl text-indigo-500 mb-12 max-w-xl font-bold leading-tight">
        ¡Pinta tu dibujo real y observa cómo se vuelve de verdad!
      </p>
      <div className="flex flex-col sm:flex-row gap-6">
        <MagicButton onClick={() => setState('SELECT_TEMPLATE')} variant="primary" className="text-3xl px-16 py-8">
          ¡A PINTAR! 🚀
        </MagicButton>
        {gallery.length > 0 && (
          <MagicButton onClick={() => setState('GALLERY')} variant="secondary" className="text-xl">
            Ver Álbum 📸
          </MagicButton>
        )}
      </div>
    </div>
  );

  const renderSelectTemplate = () => (
    <div className="max-w-5xl mx-auto p-6 text-center animate-fade-in">
      <h2 className="text-5xl font-black text-indigo-700 mb-12 drop-shadow-sm uppercase">Escoge a tu nuevo amigo</h2>
      <div className="grid grid-cols-2 sm:grid-cols-2 md:grid-cols-4 gap-8">
        {BASE_ANIMALS.map((animal) => (
