  const renderGallery = () => (
    <div className="max-w-7xl mx-auto p-6 animate-fade-in">
      <div className="flex flex-col md:flex-row justify-between items-center mb-20 gap-10">
        <h2 className="text-7xl font-black text-indigo-700 tracking-tighter drop-shadow-xl">MI ÁLBUM MÁGICO</h2>
        <MagicButton onClick={() => setState('SELECT_TEMPLATE')} variant="primary" className="text-3xl px-16 py-6">
          + Nuevo Amigo
        </MagicButton>
      </div>

      {gallery.length === 0 ? (
        <div className="text-center py-32 bg-white/50 rounded-[5rem] border-8 border-dashed border-indigo-200">
           <span className="text-9xl mb-10 block opacity-50">🖼️</span>
           <p className="text-4xl font-black text-indigo-300">¡Aún no tienes amigos en tu álbum!</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-16">
          {gallery.map((p, idx) => (
            <div 
              key={idx} 
              className="bg-white p-10 rounded-[5rem] shadow-2xl hover:scale-105 transition-all cursor-pointer group border-b-[20px] border-indigo-100" 
              onClick={() => { setPet(p); setState('RESULT'); }}
            >
              <div className="overflow-hidden rounded-[4rem] mb-10 aspect-square shadow-inner border-4 border-indigo-50">
                <img src={p.imageUrl} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" />
              </div>
              <h3 className="text-5xl font-black text-indigo-700 text-center uppercase tracking-tighter group-hover:text-pink-500 transition-colors">{p.name}</h3>
              <p className="text-center text-2xl font-bold text-indigo-300 mt-2">{p.baseAnimal} de {p.element}</p>
            </div>
          ))}
        </div>
      )}

      <button onClick={() => setState('HOME')} className="mt-32 block mx-auto text-4xl font-black text-indigo-200 hover:text-indigo-600 transition-colors uppercase tracking-widest">← Volver al Inicio</button>
    </div>
  );

  return (
    <div className="min-h-screen magic-bg pb-32">
      <header className="p-8 flex justify-between items-center bg-white/60 backdrop-blur-3xl sticky top-0 z-50 border-b-8 border-white shadow-lg">
        <div className="text-5xl font-black text-indigo-700 cursor-pointer flex items-center gap-6 group" onClick={() => setState('HOME')}>
          <span className="text-7xl group-hover:rotate-12 transition-transform duration-500">🪄</span> 
          <span className="hidden md:block tracking-tighter">MUNDO MÁGICO</span>
        </div>
        <div className="flex gap-6">
          {gallery.length > 0 && (
            <button onClick={() => setState('GALLERY')} className="bg-white p-6 rounded-full shadow-2xl text-5xl hover:scale-110 active:scale-90 transition-all border-4 border-indigo-50">🖼️</button>
          )}
          <button onClick={() => setState('HOME')} className="bg-white p-6 rounded-full shadow-2xl text-5xl hover:scale-110 active:scale-90 transition-all border-4 border-indigo-50">🏠</button>
        </div>
      </header>

      <main className="container mx-auto px-6 mt-16 relative z-10">
        {loading ? (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center">
            <div className="w-80 h-80 relative flex items-center justify-center">
               <div className="absolute inset-0 border-x-[20px] border-indigo-600 rounded-full animate-spin"></div>
               <div className="absolute inset-6 border-y-[20px] border-pink-400 rounded-full animate-spin-slow"></div>
               <span className="text-[10rem] animate-bounce drop-shadow-2xl">✨</span>
            </div>
            <p className="mt-24 text-6xl font-black text-indigo-700 animate-pulse px-10 leading-tight drop-shadow-xl">{loadingMsg}</p>
          </div>
        ) : (
          <>
            {state === 'HOME' && renderHome()}
            {state === 'SELECT_TEMPLATE' && renderSelectTemplate()}
            {state === 'CREATOR' && renderCreator()}
            {state === 'RESULT' && renderResult()}
            {state === 'GALLERY' && renderGallery()}
          </>
        )}
      </main>

      <footer className="mt-40 py-16 text-center opacity-40 border-t-4 border-indigo-100">
        <p className="text-indigo-900 font-black text-2xl tracking-widest">CREADO CON MAGIA PURA ✨ 2024</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { BASE_ANIMALS, COLORS_BY_NUMBER } from '../constants';

interface ColorByNumberProps {
  animalId: string;
  selectedNumber: number;
  onColored: (dataUrl: string) => void;
}

const ColorByNumber: React.FC<ColorByNumberProps> = ({ animalId, selectedNumber, onColored }) => {
  const animal = BASE_ANIMALS.find(a => a.id === animalId) || BASE_ANIMALS[0];
  const [fills, setFills] = useState<Record<string, string>>({});
  const containerRef = useRef<HTMLDivElement>(null);

  const handleRegionClick = (regionId: string) => {
    const colorObj = COLORS_BY_NUMBER.find(c => c.n === selectedNumber);
    if (colorObj) {
      const newFills = { ...fills, [regionId]: colorObj.color };
      setFills(newFills);
    }
  };

  useEffect(() => {
    if (containerRef.current) {
      const svg = containerRef.current.querySelector('svg');
      if (svg) {
        const svgData = new XMLSerializer().serializeToString(svg);
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        const img = new Image();
        const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
        const url = URL.createObjectURL(svgBlob);

        img.onload = () => {
          canvas.width = 1024;
          canvas.height = 1024;
          if (ctx) {
            ctx.fillStyle = 'white';
            ctx.fillRect(0, 0, 1024, 1024);
            ctx.drawImage(img, 0, 0, 1024, 1024);
            onColored(canvas.toDataURL('image/png'));
          }
          URL.revokeObjectURL(url);
        };
        img.src = url;
      }
    }
  }, [fills]);

  return (
    <div ref={containerRef} className="w-full flex justify-center bg-white p-10 rounded-[4rem] shadow-2xl border-8 border-indigo-100 relative group overflow-hidden">
      <div className="absolute inset-0 bg-indigo-50/20 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />
      <svg viewBox="0 0 100 130" className="w-full max-w-[500px] aspect-square select-none touch-none relative z-10">
        <defs>
          <filter id="beautyShadow" x="-20%" y="-20%" width="140%" height="140%">
            <feGaussianBlur in="SourceAlpha" stdDeviation="1.2" />
            <feOffset dx="0.5" dy="0.5" result="offsetblur" />
            <feComponentTransfer>
              <feFuncA type="linear" slope="0.15" />
            </feComponentTransfer>
            <feMerge>
              <feMergeNode />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
        </defs>

        {/* Zonas de color */}
        {Object.entries(animal.pathData).map(([num, path]) => {
          const pos = animal.numberPositions[num] || { x: 50, y: 50 };
          return (
            <g key={num} onClick={() => handleRegionClick(num)} className="cursor-pointer">
              <path
                d={path}
                fill={fills[num] || '#ffffff'}
                stroke="#f1f5f9"
                strokeWidth="0.5"
                filter="url(#beautyShadow)"
                className="transition-colors duration-500"
              />
              {!fills[num] && (
                <g className="pointer-events-none">
                  <circle cx={pos.x} cy={pos.y} r="5" fill="white" fillOpacity="0.9" />
                  <text
                    x={pos.x}
                    y={pos.y}
                    textAnchor="middle"
                    className="text-[8px] font-black fill-indigo-200"
                    style={{ dominantBaseline: 'middle' }}
                  >
                    {num}
                  </text>
                </g>
              )}
            </g>
          );
        })}

        {/* Capa Maestra de Ilustración (El "PNG" profesional) */}
        <path
          d={animal.detailPath}
          fill="none"
          stroke="#0f172a"
          strokeWidth="1.8"
          strokeLinecap="round"
          strokeLinejoin="round"
          className="pointer-events-none opacity-90"
        />

        {/* Brillos en ojos para dar vida */}
        <g className="pointer-events-none">
           <circle cx="43.5" cy="64" r="0.8" fill="white" />
           <circle cx="53.5" cy="64" r="0.8" fill="white" />
        </g>
      </svg>
    </div>
  );
};

export default ColorByNumber;
